SET academy_metadata = '{"displayName":"Cyprus – Student Visa (Entry Permit + Pink Slip)","shortDescription":"CRMD Cyprus · VFS India · Entry Permit → Pink Slip within 7 days","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 10 Jun 2026","learningLevel":"Intermediate","learningMinutes":24,"policyAlert":{"active":true,"date":"10 Jun 2026","summary":"Cyprus is NOT Schengen — Pink Slip does not allow EU travel. Confirm fees at visa.vfsglobal.com/cyprus/india."},"alert":{"title":"Two-stage visa + NOT Schengen","body":"Entry Permit before travel; Pink Slip within 7–10 days of arrival. Cyprus residence permit does NOT allow Schengen travel without a separate visa. Confirm institution is in South Cyprus (EU), not TRNC."},"tags":[{"label":"Active service","variant":"success"},{"label":"PCC apostille critical","variant":"warning"},{"label":"4–8 weeks","variant":"neutral"},{"label":"VFS appointment","variant":"neutral"},{"label":"NOT Schengen","variant":"warning"}],"chips":[{"label":"4–8 weeks","variant":"neutral"},{"label":"€60–90 Entry Permit","variant":"neutral"},{"label":"Pink Slip 7 days","variant":"warning"},{"label":"NOT Schengen travel","variant":"warning"}],"kpis":[{"label":"Processing time","value":"4–8w","sub":"Entry Permit via VFS India","tone":"primary"},{"label":"Government fee","value":"€60–90","sub":"+ Pink Slip €70–140 after arrival","tone":"warning"},{"label":"Our approval rate","value":"90%","sub":"~78% benchmark","tone":"success"},{"label":"Required docs","value":"18","sub":"+ PCC apostille & medical panel","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Two-stage student immigration: (1) Entry Permit obtained from India via VFS Global or university-assisted CRMD route before travel; (2) Temporary Residence Permit (Pink Slip) at local CRMD within 7–10 days of arrival in Cyprus."},{"label":"Eligible applicants","value":"Unconditional offer from CRMD-recognised institution · Full-time study (min. 12 credits/semester) · PCC apostilled + Cyprus Embassy attested · Medical panel (HIV, Hep B/C, Syphilis, TB — 4-month validity) · Financial proof €7,000–€10,000+"},{"label":"Proof of funds","value":"No official published minimum; benchmark €7,000–€10,000 in bank with 3–6 months history. Tuition deposit (€2,000–€5,000) typically required before offer confirmation.","warning":true},{"label":"Key authority","value":"CRMD Cyprus (crmd.moi.gov.cy) · VFS Global Cyprus India (visa.vfsglobal.com/cyprus/india) · Cyprus Embassy in India (PCC attestation)"},{"label":"After approval","value":"Travel on Entry Permit; register at university on first working day; apply for Pink Slip at CRMD within 7–10 days; register with GHS (gesy.org.cy); renew Pink Slip annually."},{"label":"TRNC warning","value":"North Cyprus (TRNC) institutions are NOT EU-recognised. Degrees from TRNC cannot be used for EU employment or NMC licensing in India. Always confirm South Cyprus (Republic of Cyprus) institution.","warning":true}],"eligibility":[{"criterion":"Unconditional offer from CRMD-recognised institution","met":true},{"criterion":"PCC apostilled (MEA) + Cyprus Embassy attested","met":false,"note":"Start immediately — allow 4–6 weeks"},{"criterion":"Medical panel (HIV, Hep B/C, Syphilis, TB — valid 4 months)","met":false,"note":"Time tests for application date"},{"criterion":"Financial proof €7,000–€10,000+","met":false,"note":"3–6 months bank history; sponsor acceptable"},{"criterion":"Proof of accommodation in Cyprus","met":false},{"criterion":"Tuition deposit paid (university receipt)","met":false},{"criterion":"Valid passport (1+ year beyond arrival)","met":true},{"criterion":"English proficiency or university waiver","met":true,"note":"IELTS 5.5–6.5 typical; some waive"}],"redFlagsBanner":"After refusal, address PCC/medical/financial gaps before rebooking. Never advise TRNC institutions as EU-equivalent.","r